"use client";

import { useMemo, useRef, useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { getRandomComplete, triggerShake } from "@/lib/learningMessages";

// ===== 网格规格：8 列 × 6 行 =====
const COLS = 8;
const ROWS = 6;
const TOTAL = COLS * ROWS;

interface Scenario {
  id: string;
  icon: string;
  title: string;
  question: string;
  length: number; // 长（米）对应列数
  width: number; // 宽（米）对应行数
  answer: number; // length * width
  unit: string;
}

const SCENARIOS: Scenario[] = [
  {
    id: "floor",
    icon: "🏠",
    title: "铺地板",
    question:
      "小明家要铺地板，房间长 4 米、宽 3 米，每块地砖是 1 平方米，需要几块？",
    length: 4,
    width: 3,
    answer: 12,
    unit: "地砖",
  },
  {
    id: "wall",
    icon: "🧱",
    title: "贴瓷砖",
    question: "墙壁长 3 米、高 2 米，每块瓷砖 1 平方米，需要几块瓷砖？",
    length: 3,
    width: 2,
    answer: 6,
    unit: "瓷砖",
  },
];

type Phase = "draw" | "answer" | "done";

export default function ApplyPage() {
  const [scenarioIdx, setScenarioIdx] = useState(0);
  const scenario = SCENARIOS[scenarioIdx];
  const target = scenario.answer;

  const [cells, setCells] = useState<boolean[]>(
    Array.from({ length: TOTAL }, () => false)
  );
  const [phase, setPhase] = useState<Phase>("draw");
  const [answer, setAnswer] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");
  const [showHint, setShowHint] = useState(false);
  const [highlightDiff, setHighlightDiff] = useState(false);
  const [doneSet, setDoneSet] = useState<Set<string>>(new Set());

  const gridRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const filledCount = cells.filter(Boolean).length;
  const reachedTarget = filledCount === target;

  // 已填充区域的边界框（用于在图上标注尺寸）
  const bounds = useMemo(() => {
    let minR = ROWS,
      maxR = -1,
      minC = COLS,
      maxC = -1;
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        if (cells[r * COLS + c]) {
          if (r < minR) minR = r;
          if (r > maxR) maxR = r;
          if (c < minC) minC = c;
          if (c > maxC) maxC = c;
        }
      }
    }
    if (maxR < 0) return null;
    return {
      minR,
      minC,
      width: maxC - minC + 1,
      height: maxR - minR + 1,
    };
  }, [cells]);

  const isSolidRectangle =
    bounds !== null && bounds.width * bounds.height === filledCount;

  const toggleCell = (idx: number) => {
    if (phase !== "draw") return;
    setCells((prev) => {
      const next = [...prev];
      next[idx] = !next[idx];
      return next;
    });
  };

  const handleDrawDone = () => {
    if (!reachedTarget) return;
    setPhase("answer");
    setShowHint(false);
    setTimeout(() => inputRef.current?.focus(), 100);
  };

  const handleSubmitAnswer = () => {
    if (!answer) return;
    if (Number(answer) === target) {
      setPhase("done");
      setCompleteMsg(getRandomComplete());
      setHighlightDiff(false);
      setShowHint(false);
      setDoneSet((prev) => new Set(prev).add(scenario.id));
    } else {
      // 答错：不显示"错了"，而是抖动 + 高亮差异区域引导重数
      triggerShake(inputRef.current);
      triggerShake(gridRef.current);
      setHighlightDiff(true);
      setShowHint(true);
      setAnswer("");
      setTimeout(() => setHighlightDiff(false), 2500);
    }
  };

  const resetScenario = () => {
    setCells(Array.from({ length: TOTAL }, () => false));
    setPhase("draw");
    setAnswer("");
    setShowHint(false);
    setHighlightDiff(false);
  };

  const switchScenario = (idx: number) => {
    if (idx === scenarioIdx) return;
    setScenarioIdx(idx);
    resetScenario();
  };

  const nextStep = getNextStep("area", "apply");
  const anyDone = doneSet.size > 0;
  const allDone = SCENARIOS.every((s) => doneSet.has(s.id));

  // 显示尺寸标注：答题/完成阶段，或画图阶段已达到目标格数
  const showDims = bounds !== null && (phase !== "draw" || reachedTarget);

  // ===== 渲染网格（含行列号与尺寸标注） =====
  const renderGrid = () => (
    <div
      ref={gridRef}
      className="mx-auto w-full max-w-[460px] select-none"
      style={{
        display: "grid",
        gridTemplateColumns: `34px repeat(${COLS}, minmax(0, 1fr))`,
        gridTemplateRows: `30px repeat(${ROWS}, auto)`,
        gap: 4,
      }}
    >
      {/* 左上角 */}
      <div />

      {/* 列号 1..COLS */}
      {Array.from({ length: COLS }, (_, c) => (
        <div
          key={`col-${c}`}
          style={{ gridColumn: c + 2, gridRow: 1 }}
          className="flex items-center justify-center text-xs text-[var(--text-muted)]"
        >
          {c + 1}
        </div>
      ))}

      {/* 行号 1..ROWS */}
      {Array.from({ length: ROWS }, (_, r) => (
        <div
          key={`row-${r}`}
          style={{ gridColumn: 1, gridRow: r + 2 }}
          className="flex items-center justify-center text-xs text-[var(--text-muted)]"
        >
          {r + 1}
        </div>
      ))}

      {/* 格子 */}
      {Array.from({ length: TOTAL }, (_, idx) => {
        const r = Math.floor(idx / COLS);
        const c = idx % COLS;
        const filled = cells[idx];

        let cellClass: string;
        if (phase === "done" && filled) {
          cellClass = "bg-[var(--signal-success)]";
        } else if (filled) {
          cellClass = highlightDiff
            ? "animate-pulse-highlight"
            : "bg-[var(--signal-confirmed)]";
        } else {
          cellClass = "border-2 border-dashed border-[var(--signal-pending)]";
        }

        return (
          <button
            key={idx}
            type="button"
            aria-label={`格子 ${r + 1} 行 ${c + 1} 列`}
            onClick={() => toggleCell(idx)}
            disabled={phase !== "draw"}
            style={{ gridColumn: c + 2, gridRow: r + 2 }}
            className={`aspect-square w-full rounded-md transition-all duration-150 ${cellClass} ${
              phase === "draw"
                ? "cursor-pointer hover:border-[var(--signal-focus)] hover:bg-[var(--signal-focus)]/20"
                : "cursor-default"
            }`}
          />
        );
      })}

      {/* 在图上标注尺寸：长（横向） */}
      {showDims && bounds && (
        <div
          style={{
            gridColumn: `${bounds.minC + 2} / span ${bounds.width}`,
            gridRow: 1,
          }}
          className="z-10 flex items-center justify-center gap-1 rounded-md bg-[var(--signal-focus)] px-1 text-[var(--text)] shadow-[var(--shadow-sm)]"
        >
          <span className="text-xs">↔</span>
          <span className="text-base font-bold leading-none">
            {bounds.width}
          </span>
          <span className="text-[10px] leading-none">米</span>
        </div>
      )}

      {/* 在图上标注尺寸：宽（纵向） */}
      {showDims && bounds && (
        <div
          style={{
            gridColumn: 1,
            gridRow: `${bounds.minR + 2} / span ${bounds.height}`,
          }}
          className="z-10 flex flex-col items-center justify-center rounded-md bg-[var(--signal-focus)] px-1 text-[var(--text)] shadow-[var(--shadow-sm)]"
        >
          <span className="text-xs leading-none">↕</span>
          <span className="text-base font-bold leading-none">
            {bounds.height}
          </span>
          <span className="text-[10px] leading-none">米</span>
        </div>
      )}
    </div>
  );

  return (
    <StepShell topicId="area" stepId="apply">
      <div className="space-y-6">
        {/* 情境选择 */}
        <div className="flex justify-center gap-3">
          {SCENARIOS.map((s, i) => (
            <button
              key={s.id}
              onClick={() => switchScenario(i)}
              className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
                i === scenarioIdx
                  ? "bg-[var(--signal-focus)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                  : "bg-[var(--bg-soft)] text-[var(--text-secondary)] hover:bg-[var(--signal-focus)]/30"
              }`}
            >
              {s.icon} {s.title}
              {doneSet.has(s.id) && (
                <span className="ml-1 text-[var(--signal-success)]">✓</span>
              )}
            </button>
          ))}
        </div>

        {/* 情境卡片 */}
        <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <div className="flex items-start gap-4">
            <div className="text-4xl">{scenario.icon}</div>
            <div className="flex-1">
              <h2 className="text-lg font-semibold text-[var(--text)]">
                {scenario.title}
              </h2>
              <p className="mt-1 text-[var(--text-secondary)]">
                {scenario.question}
              </p>
            </div>
          </div>
        </section>

        {/* 画图阶段 */}
        {phase === "draw" && (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <div className="mb-4 text-center">
              <p className="text-sm font-medium text-[var(--text)]">
                在网格上画出房间的示意图
              </p>
              <p className="mt-1 text-xs text-[var(--text-secondary)]">
                点击格子填充，画一个长 {scenario.length} 格、宽{" "}
                {scenario.width} 格的长方形
              </p>
            </div>
            {renderGrid()}
            <div className="mt-4 flex flex-wrap items-center justify-center gap-4">
              <span className="text-sm text-[var(--text-secondary)]">
                已画{" "}
                <span className="font-bold text-[var(--text)]">
                  {filledCount}
                </span>{" "}
                格
              </span>
              {filledCount > 0 && (
                <button
                  onClick={resetScenario}
                  className="rounded-full px-4 py-2 text-sm text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
                >
                  清空
                </button>
              )}
              {reachedTarget && (
                <button
                  onClick={handleDrawDone}
                  className="animate-float-in rounded-full bg-[var(--signal-confirmed)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                >
                  我画好了 →
                </button>
              )}
            </div>
          </section>
        )}

        {/* 回答阶段 */}
        {phase === "answer" && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <div className="mb-4 text-center">
              <p className="text-sm font-medium text-[var(--text)]">
                看看你的图，需要几块{scenario.unit}？
              </p>
            </div>
            {renderGrid()}
            {showHint && (
              <p className="mt-3 text-center text-sm text-[var(--signal-shake)]">
                数一数图上的格子～
              </p>
            )}
            <div className="mt-5 flex flex-wrap items-center justify-center gap-3">
              <input
                ref={inputRef}
                type="text"
                inputMode="numeric"
                value={answer}
                onChange={(e) =>
                  setAnswer(e.target.value.replace(/[^0-9]/g, ""))
                }
                onKeyDown={(e) => e.key === "Enter" && handleSubmitAnswer()}
                className="w-28 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                placeholder="?"
              />
              <span className="text-[var(--text-secondary)]">块</span>
              <button
                onClick={handleSubmitAnswer}
                className="rounded-full bg-[var(--signal-confirmed)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
              >
                确定
              </button>
              <button
                onClick={resetScenario}
                className="rounded-full px-4 py-2 text-sm text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                重画
              </button>
            </div>
          </section>
        )}

        {/* 完成阶段 */}
        {phase === "done" && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <div className="text-5xl animate-bounce-soft">{scenario.icon}</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-[var(--text-secondary)]">
              {isSolidRectangle ? (
                <>
                  长 {bounds?.width} 米 × 宽 {bounds?.height} 米 ={" "}
                  <span className="font-bold text-[var(--text)]">{target}</span>{" "}
                  块{scenario.unit}
                </>
              ) : (
                <>
                  你画了{" "}
                  <span className="font-bold text-[var(--text)]">
                    {filledCount}
                  </span>{" "}
                  格，需要{" "}
                  <span className="font-bold text-[var(--text)]">{target}</span>{" "}
                  块{scenario.unit}
                </>
              )}
            </p>
            {renderGrid()}
            <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={resetScenario}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再画一次
              </button>
              {SCENARIOS.filter((s) => !doneSet.has(s.id)).map((s) => (
                <button
                  key={s.id}
                  onClick={() => switchScenario(SCENARIOS.indexOf(s))}
                  className="rounded-full bg-[var(--accent)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:bg-[var(--accent-dark)]"
                >
                  试试{s.title} →
                </button>
              ))}
              {anyDone && nextStep && (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--signal-confirmed)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
                >
                  下一步：{nextStep.label} →
                </Link>
              )}
            </div>
            {allDone && (
              <p className="mt-4 text-xs text-[var(--text-muted)]">
                两个情境都完成啦！图象法真有用 🎉
              </p>
            )}
          </section>
        )}
      </div>
    </StepShell>
  );
}
